{
 "level": "B1",
 "intro": "In this topic, you will learn in detail <strong>Past Perfect Passive</strong>: how to form this form, when to use it and how it differs from other past tenses.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "<strong>Subject + had + been + V3</strong>:",
 "example": "The work had been completed before the deadline."
 },
 {
 "label": "Denial",
 "color": "rose",
 "text": "<strong>Subject + had + not + been + V3</strong>:",
 "example": "The letter had not been sent before he left."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>Had + Subject + been + V3?</strong>:",
 "example": "Had the project been finished before the meeting?"
 }
 ]
}

{
 "title": "1. Structure of the Past Perfect Passive",
 "intro": "<strong>Had</strong> is the same for all persons, and <strong>been</strong> remains the same:",
 "items": [
 {
 "label": "All persons",
 "title": "had been + V3",
 "subtitle": "I/You/He/She/It/We/They had been invited."
 },
 {
 "label": "Singular",
 "title": "had been + V3",
 "subtitle": "The report had been submitted. — The report was submitted."
 },
 {
 "label": "Plural",
 "title": "had been + V3",
 "subtitle": "All tasks had been completed. - All tasks were completed."
 },
 {
 "label": "Key",
 "title": "been is the constant part",
 "subtitle": "been always precedes V3."
 }
 ]
}

{
 "title": "2. Affirmative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "Word order: <strong>Subject + had + been + V3 (+ by agent)</strong>",
 "examples": [
 {
 "en": "The project had been completed before the deadline.",
 "ua": "The project had been completed before the deadline."
 },
 {
 "en": "All the tickets had been sold before we arrived.",
 "ua": "All the tickets had been sold before we arrived."
 },
 {
 "en": "The problem had been solved by the time they called.",
 "ua": "The problem had been solved by the time they called."
 },
 {
 "en": "The documents had been signed by the manager.",
 "ua": "The documents had been signed by the manager."
 }
 ]
 },
 {
 "label": "To another past action",
 "color": "sky",
 "description": "When it is important to show that an action <strong>preceded another</strong>:",
 "examples": [
 {
 "en": "The house had been cleaned before the guests came.",
 "ua": "The house had been cleaned before the guests came."
 },
 {
 "en": "The email had been sent before he asked about it.",
 "ua": "The email had been sent before he asked about it."
 },
 {
 "en": "The decision had been made before the meeting started.",
 "ua": "The decision had been made before the meeting started."
 }
 ]
 }
 ]
}

{
 "title": "3. When to use Past Perfect Passive?",
 "sections": [
 {
 "label": "Action to another past",
 "color": "emerald",
 "description": "When one action <strong>finished earlier</strong> than another past:",
 "examples": [
 {
 "en": "The work had been finished before the boss arrived.",
 "ua": "The work had been finished before the boss arrived."
 },
 {
 "en": "The movie had been released before I heard about it.",
 "ua": "The movie had been released before I heard about it."
 },
 {
 "en": "The cake had been eaten before I got home.",
 "ua": "The cake had been eaten before I got home."
 }
 ]
 },
 {
 "label": "Until a certain point",
 "color": "blue",
 "description": "To a <strong>specific time or event</strong> in the past:",
 "examples": [
 {
 "en": "By 5 PM, the report had been submitted.",
 "ua": "By 5 PM, the report had been submitted."
 },
 {
 "en": "By the end of the day, all tasks had been completed.",
 "ua": "By the end of the day, all tasks had been completed."
 },
 {
 "en": "By last week, the decision had been made.",
 "ua": "By last week, the decision had been made."
 }
 ]
 },
 {
 "label": "In stories",
 "color": "amber",
 "description": "For <strong>backstory</strong> in stories:",
 "examples": [
 {
 "en": "She found out that her car had been stolen.",
 "ua": "She found out that her car had been stolen."
 },
 {
 "en": "He discovered that the money had been hidden.",
 "ua": "He discovered that the money had been hidden."
 },
 {
 "en": "They realized the door had been left unlocked.",
 "ua": "They realized the door had been left unlocked."
 }
 ]
 }
 ]
}

{
 "title": "4. Negative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Add <strong>not</strong> after had: <strong>Subject + had + not + been + V3</strong>",
 "examples": [
 {
 "en": "The report had not been submitted by the deadline.",
 "ua": "The report had not been submitted by the deadline."
 },
 {
 "en": "The documents had not been signed before the meeting.",
 "ua": "The documents had not been signed before the meeting."
 },
 {
 "en": "The problem had not been solved when they arrived.",
 "ua": "The problem had not been solved when they arrived."
 },
 {
 "en": "The changes had not been approved yet.",
 "ua": "The changes had not been approved yet."
 }
 ]
 },
 {
 "label": "Abbreviated form",
 "color": "amber",
 "description": "Colloquially: <strong>hadn't been</strong>",
 "examples": [
 {
 "en": "The email hadn't been sent before he left.",
 "ua": "The email hadn't been sent before he left."
 },
 {
 "en": "The tasks hadn't been completed on time.",
 "ua": "The tasks hadn't been completed on time."
 },
 {
 "en": "The decision hadn't been made by then.",
 "ua": "The decision hadn't been made by then."
 }
 ]
 }
 ]
}

{
 "title": "5. Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No question",
 "color": "blue",
 "description": "<strong>Had</strong> comes out on top: <strong>Had + Subject + been + V3?</strong>",
 "examples": [
 {
 "en": "Had the report been finished before the meeting?",
 "ua": "Had the report been finished before the meeting?"
 },
 {
 "en": "Had the documents been signed?",
 "ua": "Had the documents been signed?"
 },
 {
 "en": "Had the problem been solved by then?",
 "ua": "Had the problem been solved by then?"
 },
 {
 "en": "Had you ever been interviewed before?",
 "ua": "Had you ever been interviewed before?"
 }
 ]
 },
 {
 "label": "Wh question",
 "color": "sky",
 "description": "<strong>Wh-word + had + Subject + been + V3?</strong>",
 "examples": [
 {
 "en": "What had been done before he arrived?",
 "ua": "What had been done before he arrived?"
 },
 {
 "en": "Why had the meeting been cancelled?",
 "ua": "Why had the meeting been cancelled?"
 },
 {
 "en": "Where had the money been hidden?",
 "ua": "Where had the money been hidden?"
 },
 {
 "en": "How had the problem been solved?",
 "ua": "How had the problem been solved?"
 }
 ]
 },
 {
 "label": "Short answers",
 "color": "amber",
 "description": "Answers with <strong>Yes/No + pronoun + had (not)</strong>:",
 "examples": [
 {
 "en": "Had the email been sent? — Yes, it had. / No, it hadn't.",
 "ua": "Had the email been sent? — Yes, it had. / No, it hadn't."
 },
 {
 "en": "Had they been informed? — Yes, they had. / No, they hadn't.",
 "ua": "Had they been informed? — Yes, they had. / No, they hadn't."
 }
 ]
 }
 ]
}

{
 "title": "6. Comparison of Active vs Passive in Past Perfect",
 "intro": "How to turn an active sentence into a passive:",
 "rows": [
 {
 "en": "Active: They had completed the project.",
 "ua": "Active: They had completed the project.",
 "note": "→ Passive: The project had been completed."
 },
 {
 "en": "Active: Someone had stolen my bike.",
 "ua": "Active: Someone had stolen my bike.",
 "note": "→ Passive: My bike had been stolen."
 },
 {
 "en": "Active: The company had hired new staff.",
 "ua": "Active: The company had hired new staff.",
 "note": "→ Passive: New staff had been hired."
 },
 {
 "en": "Active: We had made a decision.",
 "ua": "Active: We had made a decision.",
 "note": "→ Passive: A decision had been made."
 }
 ],
 "warning": "📌 Time markers (before, by the time, already) remain!"
}

{
 "title": "7. Comparison of all Past Passive forms",
 "intro": "The difference between the three forms of the past tense in the passive:",
 "rows": [
 {
 "en": "Past Simple: The room was cleaned yesterday.",
 "ua": "Past Simple: The room was cleaned yesterday.",
 "note": "→ A fact in the past"
 },
 {
 "en": "Past Continuous: The room was being cleaned when I arrived.",
 "ua": "Past Continuous: The room was being cleaned when I arrived.",
 "note": "→ Continuous action in the past moment"
 },
 {
 "en": "Past Perfect: The room had been cleaned before I arrived.",
 "ua": "Past Perfect: The room had been cleaned before I arrived.",
 "note": "→ Action to another past"
 }
 ],
 "warning": "📌 Past Perfect Passive emphasizes that the action PRECEDED another past event!"
}

{
 "title": "8. Time markers for the Past Perfect Passive",
 "intro": "Typical words and expressions indicating the Past Perfect:",
 "items": [
 {
 "label": "To",
 "title": "Grammar focus",
 "subtitle": "The report had been submitted before noon."
 },
 {
 "label": "Already",
 "title": "already, yet, still",
 "subtitle": "The task had already been completed."
 },
 {
 "label": "Just",
 "title": "just, recently",
 "subtitle": "The email had just been sent when he arrived."
 },
 {
 "label": "Experience",
 "title": "ever, never, before",
 "subtitle": "Had this method ever been used before?"
 }
 ]
}

{
 "title": "9. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Skip been.",
 "wrong": "The report had completed before.",
 "right": "✅ The report had been completed before."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Confusion of been and being.",
 "wrong": "The work had being done.",
 "right": "✅ The work had been done."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using was instead of had.",
 "wrong": "The letter was been sent before.",
 "right": "✅ The letter had been sent before."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Past Simple instead of Past Perfect.",
 "wrong": "The email was sent before he arrived.",
 "right": "✅ The email had been sent before he arrived."
 }
 ]
}
